mapper.select:
select
, lm.ID as learningModelId , lm.LEARN_NAME from CARD_INPUT ci left join CARD_OUTPUT co ON ci.TSTM_YMD = co.TSTM_YMD AND ci.TSTM_NO = co.TSTM_NO AND ci.BRCD = co.BRCD left join LEARNING_MODEL lm on co.LEARNING_MODEL_ID = lm.ID where ci.BRCD is not null
AND ci.TSTM_YMD = #{tstmYmd} AND ci.TSTM_NO = #{tstmNo} AND ci.BRCD = #{brcd}
AND ci.NO = #{no}
